#!/usr/bin/env python3
"""Add property edit modal — edit address, price, beds, baths, etc."""
import base64, os, sys
if not os.path.exists("frontend/src/pages"):
    print("Error: Run from ~/seller-portal"); sys.exit(1)
content = base64.b64decode("")
with open("frontend/src/pages/AdminPropertyDetail.jsx", "wb") as f:
    f.write(content)
print(f"  Updated: AdminPropertyDetail.jsx ({len(content):,} bytes)")
print("\nNow run:")
print('  git add -A && git commit -m "Property edit modal: address, price, beds, baths, MLS, status" && git push')
